#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
long long n,m,a[N],s[N*4],mx[N*4];

int ls(int x){return (x<<1);}
int rs(int x){return (x<<1|1);}

void push_up(int x){
    s[x]=s[ls(x)]+s[rs(x)];
    mx[x]=max(mx[ls(x)],mx[rs(x)]);
    return;
}
void build(int x,int l,int r){
    if(l==r){
        s[x]=a[l];
        mx[x]=a[l];
        return;
    }
    int mid=(l+r)/2;
    build(ls(x),l,mid);
    build(rs(x),mid+1,r);
    push_up(x);return;
}
void change(int x,int l,int r,int L,int R){
    if(r<L||R<l)return;
    if(L<=l&&r<=R&&l==r){
        s[x]=sqrt(s[x]);
        mx[x]=sqrt(mx[x]);
        return;
    }
    int mid=(l+r)>>1;
    if(mx[ls(x)]>1)change(ls(x),l,mid,L,R);
    if(mx[rs(x)]>1)change(rs(x),mid+1,r,L,R);
    push_up(x);return;
}
long long ask(int x,int l,int r,int L,int R){
    if(r<L||R<l)return 0;
    if(L<=l&&r<=R)return s[x];
    int mid=(l+r)>>1;
    return ask(ls(x),l,mid,L,R)+ask(rs(x),mid+1,r,L,R);
}

int main(){
    cin>>n;
    for(int i=1;i<=n;i++)cin>>a[i];
    build(1,1,n);
    cin>>m;
    while(m--){
        int opt,x,y;
        cin>>opt>>x>>y;
        if(x>y)swap(x,y);
        if(opt==0)change(1,1,n,x,y);
        else cout<<ask(1,1,n,x,y)<<"\n";
    }
    return 0;
}
